INSERT INTO public.blog_posts (title, slug, category, author, excerpt, published, published_at, content) VALUES
(
  'Fruktbud för företag – Så väljer du rätt fruktleverantör',
  'fruktbud-foretag-valj-ratt-fruktleverantor',
  'tips',
  'Vitaminkorgen',
  'Guide till att välja rätt fruktbud för ditt företag. Jämför leverantörer, priser och service – hitta det bästa fruktbudet för er arbetsplats.',
  true,
  '2026-04-12T08:00:00Z',
  E'## Fruktbud för företag – Så väljer du rätt fruktleverantör\n\nAtt anlita ett **fruktbud för företag** har blivit en självklarhet för många arbetsgivare i Sverige. Men hur väljer man rätt leverantör bland alla alternativ? I den här guiden går vi igenom vad du bör tänka på när du väljer fruktbud till ditt företag.\n\n## Vad gör ett fruktbud?\n\nEtt fruktbud är en leveranstjänst som regelbundet levererar **färsk frukt direkt till ditt kontor**. Tjänsten inkluderar vanligtvis:\n\n- Inköp och kvalitetskontroll av frukt\n- Packning och leverans till er dörr\n- Flexibla leveransscheman\n- Fakturering – ofta månadsvis\n\nDet bästa med ett fruktbud är att **ni slipper all administration**. Ingen behöver åka och handla, och frukten kommer automatiskt varje vecka.\n\n## 5 saker att tänka på när du väljer fruktbud\n\n### 1. Kvalitet på frukten\n\nDen viktigaste faktorn. Billig frukt som ingen vill äta är bortkastade pengar. Fråga potentiella leverantörer:\n\n- Var kommer frukten ifrån?\n- Hur hanteras kvalitetskontrollen?\n- Packas frukten samma dag som leverans?\n\nHos Vitaminkorgen packas all frukt **samma dag som den levereras** för maximal färskhet.\n\n### 2. Leveranstider och flexibilitet\n\nKan ni välja leveransdag? Går det att pausa vid semester? Kan ni ändra beställningen med kort varsel? Ett bra fruktbud erbjuder **full flexibilitet** utan krångel.\n\n### 3. Sortiment utöver frukt\n\nMånga företag vill beställa mer än bara frukt. Kontrollera om leverantören även erbjuder:\n\n- Kaffe och te\n- Mejeri och havremjölk\n- Snacks och nötter\n- Läsk och dryck\n- Städprodukter\n\nVitaminkorgen erbjuder ett **komplett kontorssortiment** som levereras tillsammans med fruktkorgen.\n\n[Se hela vårt sortiment](/produkter)\n\n### 4. Leveransområde\n\nSäkerställ att fruktbudet levererar till just ert kontor. Vitaminkorgen levererar fraktfritt i **Stockholm, Södertälje och Uppsala**.\n\n### 5. Pris och transparens\n\nJämför priser, men glöm inte att räkna med frakt och eventuella tilläggsavgifter. Hos Vitaminkorgen ingår **fraktfri leverans** i priset – inga dolda kostnader.\n\n## Vad kostar ett fruktbud?\n\nPriserna varierar beroende på typ av fruktkorg och antal leveranser. Här är en översikt:\n\n| Fruktkorg | Pris från | Passar |\n|-----------|-----------|--------|\n| Banan | 199 kr/vecka | Aktiva kontor |\n| Original | 230 kr/vecka | 5–8 personer |\n| Premium | 340 kr/vecka | 8–15 personer |\n\n## Varför välja Vitaminkorgen som ert fruktbud?\n\n- **Dagsfärsk frukt** – Packas samma dag som leverans\n- **Fraktfritt** – Inga dolda avgifter\n- **Komplett sortiment** – Frukt, kaffe, mejeri och mer\n- **Flexibelt** – Pausa, ändra eller avsluta när ni vill\n- **Gratis provkorg** – Testa innan ni bestämmer er\n\n[Beställ en gratis provkorg](/provkorg)\n\n## Kom igång idag\n\nVill ni ha ett pålitligt fruktbud till ert företag? Kontakta oss så hjälper vi er.\n\n- Ring: [010-183 98 36](tel:010-1839836)\n- E-post: [info@vitaminkorgen.se](mailto:info@vitaminkorgen.se)\n- [Begär offert](/kontakt)\n\n**Vitaminkorgen – Ert fruktbud för företag sedan 2021.**'
),
(
  'Fruktkorg företag Stockholm – Komplett guide för arbetsgivare',
  'fruktkorg-foretag-stockholm-guide',
  'tips',
  'Vitaminkorgen',
  'Allt du behöver veta om fruktkorg till företag i Stockholm. Priser, leverans, sortiment och hur du kommer igång med frukt på kontoret.',
  true,
  '2026-04-11T08:00:00Z',
  E'## Fruktkorg företag Stockholm – Allt du behöver veta\n\nLetar du efter en **fruktkorg till ditt företag i Stockholm**? Du är inte ensam. Hundratals Stockholmsföretag beställer redan fruktkorgar till sina kontor varje vecka. I den här guiden går vi igenom allt – från priser och leverans till vilken fruktkorg som passar just ert kontor.\n\n## Varför beställer företag i Stockholm fruktkorgar?\n\nStockholm är Sveriges mest konkurrensutsatta arbetsmarknad. Att erbjuda frukt på kontoret har blivit en **standard personalförmån** som de flesta medarbetare förväntar sig. Här är de vanligaste anledningarna:\n\n- **Rekrytering** – En synlig förmån som visar att ni bryr er\n- **Produktivitet** – Frukt ger jämn energi genom hela dagen\n- **Sjukfrånvaro** – Vitaminer stärker immunförsvaret\n- **Trivsel** – Gemensamma fruktpauser bygger teamkänsla\n- **Enkelt** – Allt sköts av fruktbudet\n\n## Vilka fruktkorgar finns för företag?\n\nDe flesta leverantörer i Stockholm erbjuder olika storlekar. Hos Vitaminkorgen finns tre huvudalternativ:\n\n### Fruktkorg Original\n\nVår mest populära korg. **Blandad säsongsfrukt från 4 kg** – perfekt för kontor med 5–8 medarbetare. Innehåller en mix av äpplen, bananer, päron, clementiner och annan säsongsfrukt.\n\n**Pris: från 230 kr/vecka**\n\n### Fruktkorg Premium\n\nFör kontor som vill ha det lilla extra. **Handplockat urval från 6 kg** med premium-frukter som mango, vindruvor och exotiska frukter.\n\n**Pris: från 340 kr/vecka**\n\n### Fruktkorg Banan\n\nEnbart bananer – populärt på aktiva kontor och gym. **Från 5 kg per leverans.**\n\n**Pris: från 199 kr/vecka**\n\n[Se alla våra fruktkorgar](/produkter)\n\n## Leverans av fruktkorg i Stockholm\n\nVi levererar fruktkorgar till företag i **hela Stockholmsområdet**, inklusive:\n\n- **Centrala Stockholm** – Norrmalm, Östermalm, Södermalm, Kungsholmen, Vasastan\n- **Norra Stockholm** – Solna, Sundbyberg, Danderyd, Täby, Sollentuna\n- **Södra Stockholm** – Nacka, Lidingö, Hammarby Sjöstad, Hägersten, Älvsjö\n- **Västra Stockholm** – Bromma, Vällingby, Kista, Spånga\n\n### Leveranstider\n\n- Måndag till fredag\n- Ni väljer dag och vi levererar samma dag varje vecka\n- Leverans innan lunch så att frukten är framme när ni behöver den\n\n**All frakt ingår** – inga extra kostnader.\n\n## Mer än bara frukt\n\nMånga företag i Stockholm kompletterar sin fruktkorg med:\n\n- **Kaffe och te** – Kvalitetskaffe till fikarummet\n- **Mejeri** – Mjölk, havremjölk, yoghurt\n- **Snacks** – Nötter, müslibars, torkad frukt\n- **Läsk och juice** – Mineralvatten och dryck\n- **Städprodukter** – Diskmedel, pappershanddukar\n\nAllt på **en leverans, en faktura**.\n\n[Utforska hela sortimentet](/produkter)\n\n## Så kommer ni igång\n\n1. **Beställ en gratis provkorg** – Vi levererar utan kostnad\n2. **Välj fruktkorg och leveransdag** – Vi hjälper er hitta rätt\n3. **Njut av färsk frukt varje vecka** – Automatiskt, utan krångel\n\nIngen bindningstid. Är ni inte nöjda kan ni avsluta när ni vill.\n\n[Beställ gratis provkorg](/provkorg)\n\n## Vanliga frågor om fruktkorg för företag\n\n**Kan vi pausa vid semester?**\nJa, ni pausar enkelt via kundportalen eller genom att kontakta oss.\n\n**Vad händer om vi vill ändra storlek?**\nNi kan byta fruktkorg eller justera mängden när som helst.\n\n**Kan vi beställa till flera kontor?**\nAbsolut. Många av våra kunder har leveranser till flera adresser i Stockholm.\n\n## Kontakta oss\n\n- Ring: [010-183 98 36](tel:010-1839836)\n- E-post: [info@vitaminkorgen.se](mailto:info@vitaminkorgen.se)\n- [Begär en skräddarsydd offert](/kontakt)\n\n**Över 150 företag i Stockholm har redan valt Vitaminkorgen. Gör som dem – [kom igång idag](/provkorg).**'
),
(
  'Fruktkorg leverans Stockholm – Fraktfritt till hela Stockholmsområdet',
  'fruktkorg-leverans-stockholm-fraktfritt',
  'tips',
  'Vitaminkorgen',
  'Så fungerar fruktkorg-leverans i Stockholm. Leveransområden, tider och fraktfri leverans till kontor i hela Stockholmsområdet.',
  true,
  '2026-04-10T08:00:00Z',
  E'## Fruktkorg leverans Stockholm – Så fungerar det\n\nEn av de vanligaste frågorna vi får är: **\"Levererar ni till vårt kontor?\"** Svaret är nästan alltid ja. Vi levererar fruktkorgar fraktfritt till kontor i hela Stockholmsområdet – och även till Södertälje och Uppsala.\n\n## Leveransområden i Stockholm\n\nVi täcker **hela Storstockholm**, indelat i följande zoner:\n\n### Centrala Stockholm\n\n- Norrmalm och City\n- Östermalm\n- Södermalm\n- Kungsholmen\n- Vasastan\n- Gamla Stan\n\n### Norra förorter\n\n- Solna och Sundbyberg\n- Danderyd och Djursholm\n- Täby och Vallentuna\n- Sollentuna och Upplands Väsby\n- Kista och Akalla\n\n### Södra förorter\n\n- Nacka och Saltsjöbaden\n- Lidingö\n- Hammarby Sjöstad\n- Hägersten och Liljeholmen\n- Älvsjö och Bandhagen\n- Huddinge och Flemingsberg\n\n### Västra förorter\n\n- Bromma och Alvik\n- Vällingby och Hässelby\n- Spånga och Tensta\n- Jakobsberg och Barkarby\n\n### Utanför Stockholm\n\n- **Södertälje** – fraktfri leverans\n- **Uppsala** – fraktfri leverans\n\n[Se alla våra leveransområden](/fruktkorg-stockholm)\n\n## Leveranstider\n\nVi levererar fruktkorgar **måndag till fredag**. Så fungerar det:\n\n| Dag | Leveranstid |\n|-----|------------|\n| Måndag–fredag | Förmiddag, innan lunch |\n\nNi väljer själva vilken veckodag ni vill ha leverans. De flesta företag väljer **måndag eller tisdag** för att frukten ska räcka hela veckan.\n\n## Hur fungerar en leverans?\n\n1. **Vi packar frukten** – Samma morgon som leverans packas er fruktkorg med dagsfärsk frukt\n2. **Fruktbudet kör ut** – Vår chaufför levererar till er adress\n3. **Leverans till dörren** – Vi lämnar korgen vid receptionen eller enligt era önskemål\n4. **Ni njuter** – Färsk frukt hela veckan\n\n### Leverans utan att ni behöver vara hemma\n\nMånga kontor har reception eller gemensamt utrymme dit vi levererar. Vi anpassar oss efter era rutiner – säg bara till var ni vill ha korgen.\n\n## Vad kostar leveransen?\n\n**Ingenting.** Alla leveranser i Stockholm, Södertälje och Uppsala är **helt fraktfria**. Priset ni ser för fruktkorgen är det ni betalar – inga dolda avgifter.\n\n## Flexibilitet i leveransen\n\n- **Pausa** – Stäng av leveransen vid semester eller konferens\n- **Ändra dag** – Byt leveransdag när det passar er\n- **Justera mängd** – Öka eller minska efter behov\n- **Lägg till produkter** – Komplettera med kaffe, mejeri eller snacks\n\nAllt hanteras enkelt via er kundportal eller genom att kontakta oss.\n\n## Beställ idag – leverans redan nästa vecka\n\nVi erbjuder snabb uppstart. Beställ innan onsdag så kan ni ha er första fruktkorg **redan nästa vecka**.\n\n- [Beställ gratis provkorg](/provkorg)\n- [Se våra fruktkorgar](/produkter)\n- Ring: [010-183 98 36](tel:010-1839836)\n\n**Vitaminkorgen – Fraktfri fruktkorg-leverans i Stockholm sedan 2021.**'
),
(
  'Fruktkorg till kontoret – Guide för att välja rätt frukt till jobbet',
  'fruktkorg-till-kontoret-guide-jobbet',
  'tips',
  'Vitaminkorgen',
  'Komplett guide till fruktkorg på kontoret. Så väljer du rätt fruktkorg till jobbet – storlekar, innehåll och tips för att maximera nyttan.',
  true,
  '2026-04-09T08:00:00Z',
  E'## Fruktkorg till kontoret – Rätt frukt till rätt arbetsplats\n\nAtt ha en **fruktkorg på kontoret** har gått från lyxig förmån till en självklarhet på de flesta arbetsplatser. Men vilken fruktkorg passar just ert kontor? Och hur maximerar ni nyttan av er investering? Den här guiden hjälper er att välja rätt.\n\n## Vilken fruktkorg passar ert kontor?\n\nRätt fruktkorg beror på **hur många ni är**, **hur ert kontor ser ut** och **vad era medarbetare föredrar**.\n\n### Litet kontor (2–5 medarbetare)\n\nFör mindre kontor rekommenderar vi **Fruktkorg Banan** eller en mindre variant av Original. Lagom mängd utan risk för svinn.\n\n- Fruktkorg Banan från 199 kr/vecka\n- Fruktkorg Original (liten) från 230 kr/vecka\n\n### Medelstort kontor (5–15 medarbetare)\n\nDet vanligaste segmentet. Här passar **Fruktkorg Original** eller **Premium** perfekt.\n\n- Fruktkorg Original – blandad säsongsfrukt, 4 kg\n- Fruktkorg Premium – handplockat urval, 6 kg\n\n### Stort kontor (15+ medarbetare)\n\nFör större kontor rekommenderar vi att **kombinera flera korgar** eller beställa i större volymer. Kontakta oss för en skräddarsydd lösning.\n\n[Begär offert för ert kontor](/kontakt)\n\n## Var ska fruktkorgen stå?\n\nPlacering är viktigare än man tror. Frukt som **syns äts mer**.\n\n### Bästa platserna för fruktkorgen\n\n- **Köket/fikarummet** – Mest naturliga platsen, nära kaffe och vatten\n- **Receptionen** – Synligt för alla som kommer och går\n- **Mötesrummet** – Hälsosamt alternativ till kakor vid möten\n- **Gemensamt kontorslandskap** – Centralt och lättillgängligt\n\n### Platser att undvika\n\n- Direkt solljus – Frukten mognar för snabbt\n- Nära element – Värme torkar ut frukten\n- Undangömda hörn – Frukt som inte syns äts inte\n\n## Tips för att maximera nyttan\n\n### 1. Kommunicera\n\nBerätta för medarbetarna att det finns frukt. Det låter självklart, men många kontor har frukt som **inte äts upp för att folk inte vet om den**.\n\n### 2. Variera\n\nSäsongsbaserad frukt ger naturlig variation. Vitaminkorgen anpassar automatiskt innehållet efter säsong.\n\n### 3. Komplettera med andra mellanmål\n\nFrukt kombinerat med **nötter, müslibars eller yoghurt** ger en komplett mellanmålsstation.\n\n### 4. Anpassa mängden\n\nBörja med en provkorg och justera sedan. Det är bättre att **beställa lite för lite och öka** än att ha mycket svinn.\n\n## Fruktkorg som del av er hälsostrategi\n\nAllt fler företag integrerar fruktkorgen i sin **friskvårdssatsning**. Frukt på jobbet kan:\n\n- Vara en del av er **hälsopolicy**\n- Ingå i ert **CSR-arbete**\n- Användas i **employer branding**\n- Bidra till **minskad sjukfrånvaro**\n\n## Frukt till jobbet – Mer än bara fruktkorg\n\nFörutom klassiska fruktkorgar erbjuder vi:\n\n- **Fruktpåsar** – Individuella portioner, perfekt för hybridkontor\n- **Smoothie-kit** – Allt för att göra smoothies på kontoret\n- **Fruktlådor** – Större format för evenemang\n\n[Se hela sortimentet](/produkter)\n\n## Kom igång med fruktkorg till kontoret\n\nVi erbjuder en **kostnadsfri provkorg** utan bindningstid. Testa och se vad era medarbetare tycker.\n\n1. [Beställ gratis provkorg](/provkorg)\n2. Vi levererar inom en vecka\n3. Ni bestämmer om ni vill fortsätta\n\nRing: [010-183 98 36](tel:010-1839836) | E-post: [info@vitaminkorgen.se](mailto:info@vitaminkorgen.se)\n\n**Vitaminkorgen – Fruktkorg till kontoret i Stockholm sedan 2021.**'
);